INSERT INTO public.agents (slug, name, description, category, icon, credit_cost, active) VALUES
('revisor-sistematico', 'Revisor Sistemático e Assistente de Metanálise', 'Estruture revisões sistemáticas completas seguindo PRISMA 2020: protocolo PICO, estratégia de busca em múltiplas bases, fluxograma de seleção, avaliação de risco de viés (RoB 2/Newcastle-Ottawa), síntese GRADE e orientações para metanálise.', 'Pesquisa Acadêmica e Dados', 'ClipboardList', 1, true),
('escrita-cientifica', 'Assistente de Escrita Científica e Formatação', 'Revise manuscritos acadêmicos com diagnóstico completo: notas por aspecto (IMRAD, coerência, voz), revisão parágrafo a parágrafo com track-changes simulado, checklist por seção e formatação de referências (Vancouver, APA, ABNT).', 'Pesquisa Acadêmica e Dados', 'FileText', 1, true),
('referencial-teorico', 'Gerador de Referencial Teórico e Revisão de Literatura', 'Estruture a fundamentação teórica de dissertações e teses: mapa conceitual hierárquico, autores seminais sugeridos, templates de parágrafos acadêmicos, framework conceitual e identificação de gaps na literatura.', 'Pesquisa Acadêmica e Dados', 'BookOpen', 1, true),
('propriedade-intelectual', 'Consultor de Propriedade Intelectual e Patentes', 'Avalie a patenteabilidade de inovações farmacêuticas e de saúde: requisitos da Lei 9.279/96, grace period, busca de anterioridade (INPI/Espacenet/USPTO), estrutura de reivindicações e cronograma de depósito nacional e PCT.', 'Pesquisa Acadêmica e Dados', 'ShieldCheck', 1, true),
('mentor-carreira', 'Mentor de Carreira Acadêmica e Produtividade', 'Planeje sua carreira acadêmica: diagnóstico com indicadores vs. metas, estratégia de publicação e escolha de journals, preparação para concursos com barema, editais CNPq/CAPES/FAPs, cronograma 12 meses e gestão de produtividade.', 'Pesquisa Acadêmica e Dados', 'UserRound', 1, true),
('analista-qualitativo', 'Analista de Dados Qualitativos', 'Analise dados qualitativos com rigor metodológico: Bardin, Braun & Clarke, Grounded Theory, Análise de Discurso, IPA e Narrativa. Codificação, categorização temática, matriz cruzada e critérios de rigor (triangulação, saturação, member checking).', 'Pesquisa Acadêmica e Dados', 'MessageCircleHeart', 1, true);